const { appId, res, txnId } = await createSenpAppAndOffer(this, {
    'employment.emp_type':        'SELFEMP',
    'employment.annual_turnover': 'Rs.40 lakhs to 1.5 Cr.',
    'employment.nature_of_business': 'Manufacturer',
    'employment.business_type':   'Proprietorship',
}, { removeIncome: true });
expect(res.status, 'App Create (no income, has annual_turnover) must be 200').to.equal(200);
expect(appId, 'application_id must be created').to.be.a('string').and.not.be.empty;
expect(txnId, 'offer must reach Approved (txnId returned) — app moved forward without income').to.be.ok;
const bank = await advanceToBanking(this, appId);
expect(bank.bankTxnId, 'banking init must return a transactionId').to.be.ok;
expect(bank.bankingStatus, 'banking check must produce a terminal status')
    .to.be.oneOf(['Completed', 'Retry', 'Rejected']);
const omni = await fetchOmniStages(this, appId, ['OMNI_1', 'OMNI_PRE', 'OMNI_POST']);
expect(omni.OMNI_1.input, 'OMNI_1 input must be present after offer').to.exist;

